import boto3
import re

def script_handler(events, context):
  instance_id = events['InstanceId']
  instance_type = events['InstanceType']
  region = events['Region']

  xen_sriov_patterns = [r'^c3\.', r'^c4\.', r'^d2\.', r'^i2\.', r'^r3\.']
  is_m4_sriov = instance_type.startswith('m4.') and instance_type != 'm4.16xlarge'
  is_xen_sriov_type = is_m4_sriov or any(re.match(p, instance_type) for p in xen_sriov_patterns)

  if not is_xen_sriov_type:
    return {'Compatible': 'true', 'Message': 'OK: Instance type compatible (not Xen SR-IOV)'}

  ec2 = boto3.client('ec2', region_name=region)
  response = ec2.describe_instance_attribute(InstanceId=instance_id, Attribute='sriovNetSupport')

  if response.get('SriovNetSupport', {}).get('Value') == 'simple':
    raise Exception(f'INCOMPATIBLE: Instance {instance_id} has SR-IOV enabled. Migrate to Nitro instance type first.')

  return {'Compatible': 'true', 'Message': f'OK: Instance type {instance_type} is Xen but SR-IOV not enabled'}

import boto3

def script_handler(events, context):
  autoscaling = boto3.client('autoscaling', region_name=events['Region'])
  response = autoscaling.describe_auto_scaling_instances(InstanceIds=[events['InstanceId']])

  if response['AutoScalingInstances']:
    asg_name = response['AutoScalingInstances'][0]['AutoScalingGroupName']
    raise Exception(f'INCOMPATIBLE: Instance is part of ASG "{asg_name}". In-place upgrades not supported for ASG instances.')

  return {'Message': 'OK: Instance is not part of an Auto Scaling Group'}

import boto3
import json

def script_handler(events, context):
  instance_id = events['InstanceId']
  region = events['Region']

  ec2 = boto3.client('ec2', region_name=region)
  iam = boto3.client('iam')

  response = ec2.describe_instances(InstanceIds=[instance_id])
  instance = response['Reservations'][0]['Instances'][0]

  current_profile_arn = instance.get('IamInstanceProfile', {}).get('Arn', '')

  if not current_profile_arn:
    return {
      'HasSSMPermissions': 'false',
      'CurrentProfileName': '',
      'Message': 'No IAM instance profile attached'
    }

  profile_name = current_profile_arn.split('/')[-1]

  try:
    profile_response = iam.get_instance_profile(InstanceProfileName=profile_name)
    roles = profile_response['InstanceProfile'].get('Roles', [])

    if not roles:
      return {'HasSSMPermissions': 'false', 'CurrentProfileName': profile_name, 'Message': f'Profile {profile_name} has no role'}

    role_name = roles[0]['RoleName']
    attached_policies = iam.list_attached_role_policies(RoleName=role_name)['AttachedPolicies']

    has_ssm = any('AmazonSSMManagedInstanceCore' in p['PolicyArn'] or 'AmazonEC2RoleforSSM' in p['PolicyArn'] for p in attached_policies)

    if has_ssm:
      return {'HasSSMPermissions': 'true', 'CurrentProfileName': profile_name, 'Message': f'OK: Role {role_name} has SSM permissions'}

    # Check inline and customer managed policies
    all_policy_docs = []
    for policy_name in iam.list_role_policies(RoleName=role_name)['PolicyNames']:
      doc = iam.get_role_policy(RoleName=role_name, PolicyName=policy_name)['PolicyDocument']
      all_policy_docs.append(json.dumps(doc).lower())

    for p in attached_policies:
      if ':iam::' in p['PolicyArn'] and ':policy/' in p['PolicyArn']:
        try:
          policy = iam.get_policy(PolicyArn=p['PolicyArn'])
          version = iam.get_policy_version(PolicyArn=p['PolicyArn'], VersionId=policy['Policy']['DefaultVersionId'])
          all_policy_docs.append(json.dumps(version['PolicyVersion']['Document']).lower())
        except: pass

    combined = ' '.join(all_policy_docs)
    if 'ssm:' in combined and 'ssmmessages:' in combined:
      return {'HasSSMPermissions': 'true', 'CurrentProfileName': profile_name, 'Message': f'OK: Role {role_name} has SSM permissions'}

    return {'HasSSMPermissions': 'false', 'CurrentProfileName': profile_name, 'Message': f'Role {role_name} lacks SSM permissions'}

  except Exception as e:
    return {'HasSSMPermissions': 'false', 'CurrentProfileName': profile_name, 'Message': f'Error checking role: {e}'}
